const res = await page.evaluate(() => {
  // Find the main price canvas: the largest-area canvas inside the first chart table.
  const canvases = Array.from(document.querySelectorAll('canvas')) as HTMLCanvasElement[];
  let best: HTMLCanvasElement | null = null;
  for (const c of canvases) {
    if (!best || c.width * c.height > best.width * best.height) best = c;
  }
  if (!best) return { error: 'no canvas' };
  const ctx = best.getContext('2d');
  if (!ctx) return { error: 'no ctx' };
  const { width, height } = best;
  const img = ctx.getImageData(0, 0, width, height).data;
  // Background is ~ (11,15,23). Count columns that contain any green/red candle pixel.
  let colsWithCandle = 0;
  for (let x = 0; x < width; x++) {
    let has = false;
    for (let y = 0; y < height; y += 2) {
      const i = (y * width + x) * 4;
      const r = img[i], g = img[i + 1], b = img[i + 2];
      // up green ~ (38,166,154); down red ~ (239,83,80)
      const isGreen = g > 120 && r < 120 && b > 100 && b < 200;
      const isRed = r > 180 && g < 120 && b < 120;
      if (isGreen || isRed) { has = true; break; }
    }
    if (has) colsWithCandle++;
  }
  return { width, height, colsWithCandle };
});
